const APP_KEY='questlog_complete_v1';
const P2P_APP_ID='questlog.social.github.v2';
const P2P_ROOM_ID='global-48h-feed';
const POST_TTL=48*60*60*1000;
const $=(q,r=document)=>r.querySelector(q), $$=(q,r=document)=>[...r.querySelectorAll(q)];
const uid=()=>crypto.randomUUID();
const now=()=>Date.now();
const esc=s=>String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const fmt=t=>{const d=Math.max(0,now()-t),m=Math.floor(d/60000);if(m<1)return'now';if(m<60)return`${m}m`;const h=Math.floor(m/60);if(h<24)return`${h}h`;return`${Math.floor(h/24)}d`};
const expiry=t=>{const h=Math.max(0,Math.ceil((t+POST_TTL-now())/3600000));return h?`${h}h left`:'expired'};
const defaultAvatar={skin:'#d9a276',hair:'swept',hairColor:'#3b2419',eyes:'round',eyeColor:'#3ad1c7',mouth:'smile',accessory:'none',bg:'#6b3dc0'};
const freshState=()=>({version:1,me:null,profiles:{},posts:[],campaigns:[],follows:[],friends:[],blocked:[],saved:[],notifications:[],settings:{feed:'party'},seenEvents:[]});
let state=load(); let hashParts=(location.hash.slice(1)||'home').split('/'); let route=hashParts[0]; let focusedPostId=route==='post'?decodeURIComponent(hashParts.slice(1).join('/')):null; let currentFeed='party'; let p2pRoom=null; let p2pSendPost=null; let p2pSendProfile=null; let p2pSendSync=null; let p2pSendRequest=null; let p2pPeers=new Set(); let p2pPhase='connecting'; const TAB_ID=uid(); const localChannel=('BroadcastChannel' in window)?new BroadcastChannel('questlog-global-v2'):null;
function load(){try{const s=JSON.parse(localStorage.getItem(APP_KEY));return {...freshState(),...s}}catch{return freshState()}}
function save(options={}){state.posts=state.posts.filter(p=>p.createdAt+POST_TTL>now());localStorage.setItem(APP_KEY,JSON.stringify(state));if(options.broadcast!==false)localChannel?.postMessage({type:'snapshot',from:TAB_ID,data:p2pSnapshot()});renderChrome()}
function toast(msg){const t=$('#toast');t.textContent=msg;t.classList.add('show');clearTimeout(t._x);t._x=setTimeout(()=>t.classList.remove('show'),2600)}
function notify(text,routeTo='notifications'){state.notifications.unshift({id:uid(),text,createdAt:now(),read:false,route:routeTo});save()}
function avatarSVG(a=defaultAvatar){
  a={...defaultAvatar,...a};
  const hair={
    none:'',
    swept:`<path d="M19 42C18 20 31 9 50 9c18 0 31 10 33 30-11-6-17-18-31-13-11 4-16 13-33 16Z" fill="${a.hairColor}"/><path d="M27 32c8-11 19-16 35-13-12 4-19 10-24 19Z" fill="#fff" opacity=".12"/>`,
    curly:`<g fill="${a.hairColor}">${[[21,38],[24,27],[34,18],[47,15],[60,18],[71,25],[78,37],[74,48],[24,48]].map(([x,y])=>`<circle cx="${x}" cy="${y}" r="10"/>`).join('')}</g>`,
    mohawk:`<path d="M34 31 42 5l8 12 8-15 9 31-8 5H40Z" fill="${a.hairColor}"/><path d="M45 10 50 4l4 11" stroke="#fff" opacity=".18" stroke-width="3"/>`,
    long:`<path d="M15 41C15 18 29 7 50 7s36 12 36 37l-4 47H17l-3-45Z" fill="${a.hairColor}"/><path d="M23 32c9-13 21-18 38-14" fill="none" stroke="#fff" opacity=".12" stroke-width="5" stroke-linecap="round"/>`,
    braids:`<path d="M18 40C20 18 32 8 50 8c19 0 31 11 33 32-10-9-20-14-33-14-12 0-22 5-32 14Z" fill="${a.hairColor}"/><path d="M20 41c-6 15-4 31 4 45M80 41c6 15 4 31-4 45" stroke="${a.hairColor}" stroke-width="9" stroke-linecap="round"/><path d="M22 56h8m47 0h-8" stroke="#f4c66d" stroke-width="3"/>`
  }[a.hair]||'';
  const eyes={
    round:`<ellipse cx="37" cy="50" rx="5" ry="6" fill="#18101d"/><ellipse cx="63" cy="50" rx="5" ry="6" fill="#18101d"/><circle cx="37" cy="50" r="3.2" fill="${a.eyeColor}"/><circle cx="63" cy="50" r="3.2" fill="${a.eyeColor}"/><circle cx="38" cy="49" r="1" fill="#fff"/><circle cx="64" cy="49" r="1" fill="#fff"/>`,
    sharp:`<path d="M29 49q8-7 16 0-8 7-16 0Zm26 0q8-7 16 0-8 7-16 0Z" fill="#18101d"/><circle cx="37" cy="49" r="2.7" fill="${a.eyeColor}"/><circle cx="63" cy="49" r="2.7" fill="${a.eyeColor}"/>`,
    closed:`<path d="M30 50q7 7 14 0m12 0q7 7 14 0" fill="none" stroke="#38212b" stroke-width="3" stroke-linecap="round"/>`,
    glow:`<circle cx="37" cy="50" r="5" fill="${a.eyeColor}" filter="url(#glow)"/><circle cx="63" cy="50" r="5" fill="${a.eyeColor}" filter="url(#glow)"/><circle cx="37" cy="50" r="2" fill="#fff"/><circle cx="63" cy="50" r="2" fill="#fff"/>`
  }[a.eyes]||'';
  const mouth={
    smile:'<path d="M39 66q11 9 22 0" fill="none" stroke="#733f47" stroke-width="3" stroke-linecap="round"/>',
    neutral:'<path d="M41 67h18" stroke="#733f47" stroke-width="3" stroke-linecap="round"/>',
    fang:'<path d="M39 64q11 10 22 0M45 65v6m10-6v6" fill="none" stroke="#733f47" stroke-width="3" stroke-linecap="round"/>',
    grin:'<path d="M36 63q14 16 28 0Z" fill="#fff7ee" stroke="#733f47" stroke-width="2"/>'
  }[a.mouth]||'';
  const accessory={
    none:'',
    glasses:'<path d="M25 48h4m16 0h10m16 0h4" stroke="#e5d8ff" stroke-width="3"/><circle cx="37" cy="50" r="10" fill="#d7c7ff" fill-opacity=".08" stroke="#e5d8ff" stroke-width="3"/><circle cx="63" cy="50" r="10" fill="#d7c7ff" fill-opacity=".08" stroke="#e5d8ff" stroke-width="3"/>',
    scar:'<path d="m65 38-9 23m4-17 7 4" stroke="#9f4a4a" stroke-width="2.4" stroke-linecap="round"/>',
    horns:`<path d="M26 32Q8 20 18 7q3 15 18 21M74 32Q92 20 82 7q-3 15-18 21" fill="${a.hairColor}" stroke="#fff" stroke-opacity=".12"/>`,
    crown:'<path d="m24 29 5-19 14 11 8-18 11 18 13-11 2 21Z" fill="#f4c66d"/><path d="M31 26h39" stroke="#fff2b7" stroke-width="2"/>',
    patch:'<path d="M52 43h21l-3 15H54Z" fill="#25172d"/><path d="m53 44-17-10" stroke="#25172d" stroke-width="3"/>'
  }[a.accessory]||'';
  return `<svg viewBox="0 0 100 100" role="img" aria-label="Illustrated fantasy avatar"><defs><linearGradient id="bg" x1="0" y1="0" x2="1" y2="1"><stop stop-color="${a.bg}"/><stop offset="1" stop-color="#120b20"/></linearGradient><linearGradient id="cloak" x1="0" y1="0" x2="0" y2="1"><stop stop-color="#4e3764"/><stop offset="1" stop-color="#1d1427"/></linearGradient><radialGradient id="skin"><stop stop-color="#fff" stop-opacity=".24"/><stop offset=".35" stop-color="${a.skin}"/><stop offset="1" stop-color="${a.skin}"/></radialGradient><filter id="glow"><feGaussianBlur stdDeviation="2" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter><filter id="shadow"><feDropShadow dx="0" dy="4" stdDeviation="4" flood-opacity=".35"/></filter></defs><rect width="100" height="100" rx="24" fill="url(#bg)"/><circle cx="76" cy="19" r="18" fill="#fff" opacity=".055"/><path d="M9 101q6-28 41-30 35 2 41 30Z" fill="url(#cloak)"/><path d="m37 77 13 16 13-16" fill="#b88cff" opacity=".45"/><path d="M31 75q19 12 38 0" fill="none" stroke="#f4c66d" stroke-opacity=".35" stroke-width="2"/>${a.hair==='long'?hair:''}<path d="M25 45c0-21 10-31 25-31s25 10 25 31v9c0 19-11 29-25 29S25 73 25 54Z" fill="url(#skin)" filter="url(#shadow)"/><path d="M25 50q-7 1-5 10t9 7m46-17q7 1 5 10t-9 7" fill="${a.skin}"/>${a.hair!=='long'?hair:''}<path d="M31 43q6-4 13 0m12 0q7-4 13 0" fill="none" stroke="#432734" stroke-opacity=".55" stroke-width="2" stroke-linecap="round"/>${eyes}<path d="M49 54l-3 8 6 1" fill="none" stroke="#9f665c" stroke-width="2" stroke-linecap="round"/>${mouth}<path d="M34 72q16 8 32 0" fill="none" stroke="#fff" opacity=".08"/>${accessory}<rect x="1" y="1" width="98" height="98" rx="23" fill="none" stroke="#fff" stroke-opacity=".14"/></svg>`;
}
function setAvatar(el,a){if(el)el.innerHTML=avatarSVG(a)}
function ensureAccount(){if(!state.me){openAccountModal();return false}return true}
function me(){return state.me?state.profiles[state.me]:null}
function own(p){return state.me&&p.authorId===state.me}
function renderChrome(){const p=me();setAvatar($('#topAvatar'),p?.avatar);$('#topName').textContent=p?.displayName||'Guest';const unread=state.notifications.filter(n=>!n.read).length;$('#notificationBadge').textContent=unread;$('#notificationBadge').classList.toggle('hidden',!unread);$$('[data-route]').forEach(b=>b.classList.toggle('active',b.dataset.route===route));const status=$('#p2pStatus');if(status){const labels={connecting:'Connecting…',ready:`P2P ready · ${p2pPeers.size} remote`,retrying:'Reconnecting…',offline:'Local-only mode'};status.textContent=labels[p2pPhase]||labels.connecting;status.classList.toggle('online',p2pPhase==='ready');status.title=p2pPhase==='ready'?'Posts sync directly with connected browsers':'Questlog will keep retrying the peer network'}renderMiniCampaigns();renderRightSidebar()}
function renderMiniCampaigns(){const el=$('#campaignMiniList');if(!el)return;el.innerHTML=state.campaigns.length?state.campaigns.map(c=>`<button class="mini-item" data-campaign-id="${c.id}"><span class="campaign-icon" style="--accent:${c.color}">${esc(c.name.slice(0,2).toUpperCase())}</span><div><b>${esc(c.name)}</b><small>${c.nextSession?new Date(c.nextSession).toLocaleString([], {month:'short',day:'numeric',hour:'numeric',minute:'2-digit'}):'No session set'}</small></div></button>`).join(''):`<button class="mini-item" data-action="new-campaign"><span class="campaign-icon">＋</span><div><b>Create a campaign</b><small>Your first adventure</small></div></button>`}
function renderRightSidebar(){const box=$('#accountSummary');const p=me();if(box){box.innerHTML=p?`<span class="avatar avatar-lg">${avatarSVG(p.avatar)}</span><h3>${esc(p.displayName)}</h3><p>@${esc(p.handle)}</p><button class="secondary-button" data-route="profile">View profile</button>`:`<div class="empty-symbol">♙</div><h3>Join the party</h3><p>Create a local Questlog identity.</p><button class="primary-button" data-action="account">Create account</button>`}const up=$('#upcomingList');if(up)up.innerHTML=state.campaigns.filter(c=>c.nextSession).slice(0,3).map(c=>`<button class="stack-item" data-campaign-id="${c.id}"><span class="campaign-icon" style="--accent:${c.color}">${esc(c.name.slice(0,2).toUpperCase())}</span><div><b>${esc(c.name)}</b><small>${new Date(c.nextSession).toLocaleString()}</small></div></button>`).join('')||`<small class="sync-pill">No sessions scheduled</small>`;const fl=$('#followingMiniList');if(fl){const people=state.follows.map(id=>state.profiles[id]).filter(Boolean).slice(0,4);fl.innerHTML=people.map(p=>`<button class="stack-item" data-profile-id="${p.id}"><span class="avatar avatar-sm">${avatarSVG(p.avatar)}</span><div><b>${esc(p.displayName)}</b><small>@${esc(p.handle)}</small></div></button>`).join('')||`<small class="sync-pill">Follow adventurers in Discover</small>`}}
function go(r){route=r;focusedPostId=null;location.hash=r;render()}
let focusedProfileId=null;window.addEventListener('hashchange',()=>{const parts=(location.hash.slice(1)||'home').split('/');route=parts[0];focusedPostId=route==='post'?decodeURIComponent(parts.slice(1).join('/')):null;focusedProfileId=route==='profile'&&parts[1]?decodeURIComponent(parts.slice(1).join('/')):null;render()});
function render(){state.posts=state.posts.filter(p=>p.createdAt+POST_TTL>now()&&!state.blocked.includes(p.authorId));renderChrome();const v=$('#appView');({home:renderHome,campaigns:renderCampaigns,lore:renderLore,discover:renderDiscover,saved:renderSaved,notifications:renderNotifications,profile:renderProfile,post:renderFocusedPost}[route]||renderHome)(v);v.focus({preventScroll:true})}
function renderFocusedPost(v){const p=state.posts.find(x=>x.id===focusedPostId||x.shareCode===focusedPostId);v.innerHTML=`<div class="page-head focused-post-head"><div><button class="ghost-button" data-route="home">← Back to feed</button><h1>Shared tale</h1><p>This link opens the exact post while it remains live.</p></div></div><div class="feed focused-feed">${p?postHTML(p):empty('⌛','This tale is not available yet','Questlog is asking connected peers for this post. Keep this page open briefly. If no Questlog user who has the post is online, pure P2P cannot recover it.','','')}</div>`;if(!p&&p2pSendRequest)p2pSendRequest({postId:focusedPostId})}
function empty(symbol,title,text,action='',label=''){return `<section class="empty-state"><div class="empty-symbol">${symbol}</div><h2>${esc(title)}</h2><p>${esc(text)}</p>${action?`<button class="primary-button" data-action="${action}">${esc(label)}</button>`:''}</section>`}
function renderHome(v){const posts=feedPosts();v.innerHTML=`<section class="hero"><div class="hero-copy"><span class="eyebrow">YOUR ADVENTURE CONTINUES</span><h1>Every roll tells a story.</h1><p>Write session recaps, immortalise impossible dice rolls, create characters, preserve dialogue, and build living campaign lore.</p><div class="hero-actions"><button class="primary-button" data-action="open-composer">Write a tale</button><button class="secondary-button" data-action="new-campaign">Create campaign</button></div></div><button class="hero-die" data-action="quick-roll" aria-label="Roll d20"><span>20</span></button></section><section class="composer-strip"><span class="avatar avatar-md">${avatarSVG(me()?.avatar)}</span><button data-action="open-composer">What happened at the table?</button><div class="quick-types"><button data-compose-type="recap">▧ Recap</button><button data-compose-type="roll">⚄ Roll</button><button data-compose-type="character">♙ Character</button></div></section><div class="tabs"><button data-feed="party" class="${currentFeed==='party'?'active':''}">Your feed</button><button data-feed="following" class="${currentFeed==='following'?'active':''}">Following</button><button data-feed="world" class="${currentFeed==='world'?'active':''}">World</button></div><div class="feed" id="feed">${posts.length?posts.map(postHTML).join(''):empty('✦','Your chronicle is blank','Create the first real post. Questlog starts with no demo people, campaigns, or placeholder tales.','open-composer','Create the first tale')}</div>`}
function feedPosts(){let p=[...state.posts].sort((a,b)=>b.createdAt-a.createdAt);if(currentFeed==='following')p=p.filter(x=>state.follows.includes(x.authorId)||own(x));if(currentFeed==='party')p=p.filter(x=>own(x)||state.follows.includes(x.authorId)||state.campaigns.some(c=>c.id===x.campaignId));return p}
function postHTML(p){const author=state.profiles[p.authorId]||{displayName:'Unknown adventurer',handle:'unknown',avatar:defaultAvatar};const comments=p.comments||[];const liked=(p.reactions||[]).includes(state.me);const saved=state.saved.includes(p.id);return `<article class="post style-${p.style||'midnight'}" data-post-id="${p.id}"><header class="post-head"><button class="avatar avatar-md" data-profile-id="${author.id||''}">${avatarSVG(author.avatar)}</button><div class="post-author"><b>${esc(author.displayName)}</b><small><span class="post-handle">@${esc(author.handle)}</span><span>${fmt(p.createdAt)}</span><span>${expiry(p.createdAt)}</span></small></div><button class="more-button" data-more-post="${p.id}" aria-label="Post options">•••</button></header><div class="post-content"><span class="post-kicker">${labelFor(p.type)}</span><h2>${esc(p.title||fallbackTitle(p))}</h2>${p.body?`<p class="post-body">${esc(p.body)}</p>`:''}${postSpecial(p)}</div><div class="post-stats"><span>${(p.reactions||[]).length} inspirations</span><span>${comments.length} comments · ${p.shares||0} shares</span></div><div class="post-actions"><button data-react="${p.id}" class="${liked?'active':''}" aria-label="Inspire"><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.7l-1.1-1.1a5.5 5.5 0 0 0-7.8 7.8l1.1 1.1L12 21l7.8-7.5 1.1-1.1a5.5 5.5 0 0 0-.1-7.8Z"/></svg><span>Inspire</span></button><button data-comment-toggle="${p.id}" aria-label="Comment"><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M21 15a4 4 0 0 1-4 4H8l-5 3V7a4 4 0 0 1 4-4h10a4 4 0 0 1 4 4Z"/></svg><span>Comment</span></button><button data-share="${p.id}" aria-label="Share"><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M12 3v12M7 8l5-5 5 5M5 13v6a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2v-6"/></svg><span>Share</span></button><button data-save="${p.id}" class="${saved?'active':''}" aria-label="Save post"><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M6 3h12v18l-6-4-6 4Z"/></svg></button></div><section class="comments-panel hidden" id="comments-${p.id}">${comments.map(c=>commentHTML(c)).join('')}<form class="comment-form" data-comment-form="${p.id}"><input name="comment" maxlength="400" placeholder="Write a comment…" required><button class="secondary-button">Send</button></form></section></article>`}
const labelFor=t=>({recap:'SESSION RECAP',roll:'DICE ROLL',character:'CHARACTER',dialogue:'TABLE DIALOGUE',lore:'LORE ENTRY'}[t]||'TALE');
function fallbackTitle(p){return p.type==='roll'?`${p.die||'d20'} roll: ${p.result||'?'}`:p.type==='character'?p.characterName||'New character':p.type==='dialogue'?p.speaker||'Table dialogue':'Untitled tale'}
function postSpecial(p){if(p.type==='roll')return `<div class="post-media roll-display"><div class="roll-die">${esc(p.result)}</div><div><small>${esc(p.check||p.die)}</small><strong>${esc(p.die)} ${Number(p.modifier)>=0?'+':''}${esc(p.modifier||0)}</strong></div><span class="success">${Number(p.result)===Number(String(p.die).replace('d',''))?'NATURAL MAXIMUM':'ROLL RECORDED'}</span></div>`;if(p.type==='dialogue')return `<div class="post-media dialogue-box"><q>${esc(p.quote||'')}</q><small>— ${esc(p.speaker||'Unknown speaker')}${p.context?`, ${esc(p.context)}`:''}</small></div>`;if(p.type==='character')return `<div class="post-media character-card"><div class="character-avatar"><span class="avatar avatar-lg">${avatarSVG(p.characterAvatar||defaultAvatar)}</span></div><div><small>LEVEL ${esc(p.level||1)}</small><strong>${esc(p.characterName||'Unnamed hero')}</strong><p>${esc([p.race,p.className].filter(Boolean).join(' · '))}</p><div class="stat-row">${['str','dex','con','int','wis','cha'].map(k=>p[k]?`<span class="stat-pill">${k.toUpperCase()} ${esc(p[k])}</span>`:'').join('')}</div></div></div>`;if(p.type==='lore')return `<div class="post-media"><small>${esc(p.loreCategory||'World lore')}</small><p>${esc(p.loreDetail||'')}</p></div>`;return p.quote?`<div class="post-media dialogue-box"><q>${esc(p.quote)}</q><small>${esc(p.quoteBy||'From the table')}</small></div>`:''}
function commentHTML(c){const a=state.profiles[c.authorId]||{displayName:'Adventurer',avatar:defaultAvatar};return `<div class="comment"><span class="avatar avatar-sm">${avatarSVG(a.avatar)}</span><div class="comment-body"><b>${esc(a.displayName)}</b><p>${esc(c.text)}</p></div></div>`}
function renderCampaigns(v){v.innerHTML=`<div class="page-head"><div><h1>Campaigns</h1><p>Create worlds, schedule sessions, and connect posts to an adventure.</p></div><button class="primary-button" data-action="new-campaign">＋ New campaign</button></div>${state.campaigns.length?`<div class="card-grid">${state.campaigns.map(c=>`<article class="campaign-card"><div class="campaign-banner" style="--accent:${c.color}">${esc(c.name)}</div><h3>${esc(c.name)}</h3><p>${esc(c.description||'No description yet.')}</p><p>${c.system?esc(c.system):'D&D'} · ${c.nextSession?new Date(c.nextSession).toLocaleString():'No session scheduled'}</p><div class="card-actions"><button class="secondary-button" data-campaign-id="${c.id}">Open</button><button class="ghost-button" data-compose-campaign="${c.id}">New post</button></div></article>`).join('')}</div>`:empty('⚔','No campaigns yet','Create a campaign, add its details, schedule the next session, and attach posts to it.','new-campaign','Create campaign')}`}
function renderLore(v){const lore=state.posts.filter(p=>p.type==='lore').sort((a,b)=>b.createdAt-a.createdAt);v.innerHTML=`<div class="page-head"><div><h1>Lore vault</h1><p>Your worldbuilding entries, gathered in one searchable place.</p></div><button class="primary-button" data-compose-type="lore">＋ Add lore</button></div>${lore.length?`<div class="card-grid">${lore.map(p=>`<article class="lore-card"><span class="post-kicker">${esc(p.loreCategory||'WORLD LORE')}</span><h3>${esc(p.title)}</h3><p>${esc(p.body||p.loreDetail||'')}</p><div class="card-actions"><button class="secondary-button" data-open-post="${p.id}">Open post</button></div></article>`).join('')}</div>`:empty('◈','The lore vault is empty','Add places, factions, artefacts, gods, monsters, and secrets. Lore posts also appear in the main feed.','compose-lore','Write lore')}`}
function renderDiscover(v){const q=($('#globalSearch')?.value||'').trim().toLowerCase();const profiles=Object.values(state.profiles).filter(p=>p.id!==state.me&&!state.blocked.includes(p.id)&&(!q||`${p.displayName} ${p.handle} ${p.bio||''}`.toLowerCase().includes(q)));const worldPosts=state.posts.filter(p=>!state.blocked.includes(p.authorId)&&(!q||`${p.title||''} ${p.body||''}`.toLowerCase().includes(q))).sort((a,b)=>b.createdAt-a.createdAt).slice(0,8);v.innerHTML=`<div class="page-head"><div><h1>Discover</h1><p>Meet adventurers and explore public tales received through the live P2P network.</p></div><span class="sync-pill"><i class="sync-dot"></i>${p2pPhase==='ready'?`${p2pPeers.size} peers online`:'Connecting to peers'}</span></div><section class="discover-section"><div class="section-title"><h2>Adventurers</h2><span>${profiles.length}</span></div>${profiles.length?`<div class="card-grid people-grid">${profiles.map(personHTML).join('')}</div>`:empty('✦','Nobody to discover yet','Profiles appear after you receive a post or profile from another connected Questlog user.','','')}</section><section class="discover-section"><div class="section-title"><h2>World tales</h2><span>${worldPosts.length}</span></div><div class="feed">${worldPosts.length?worldPosts.map(postHTML).join(''):empty('◈','No world tales yet','Stay connected while other users publish, then their posts will appear here.','','')}</div></section>`}
function personHTML(p){const following=state.follows.includes(p.id),friend=state.friends.includes(p.id);const count=state.posts.filter(x=>x.authorId===p.id).length;return `<article class="person-card clickable-card" data-profile-id="${p.id}"><button class="avatar avatar-lg" data-profile-id="${p.id}">${avatarSVG(p.avatar)}</button><div class="person-copy"><h3>${esc(p.displayName)}</h3><p class="profile-handle">@${esc(p.handle)}</p><p>${esc(p.bio||'No bio yet')}</p><small>${count} ${count===1?'post':'posts'}</small></div><div class="card-actions"><button class="secondary-button" data-follow="${p.id}">${following?'Following':'Follow'}</button><button class="ghost-button" data-friend="${p.id}">${friend?'Friends':'Add friend'}</button><button class="ghost-button" data-profile-id="${p.id}">View profile</button></div></article>`}
function renderSaved(v){const posts=state.saved.map(id=>state.posts.find(p=>p.id===id)).filter(Boolean);v.innerHTML=`<div class="page-head"><div><h1>Saved tales</h1><p>Posts you bookmarked before their 48-hour expiry.</p></div></div><div class="feed">${posts.length?posts.map(postHTML).join(''):empty('▣','Nothing saved','Use the bookmark button on any post to keep it here while it remains live.','','')}</div>`}
function renderNotifications(v){state.notifications.forEach(n=>n.read=true);save();v.innerHTML=`<div class="page-head"><div><h1>Notifications</h1><p>Real actions from your account and posts.</p></div><button class="ghost-button" data-action="clear-notifications">Clear all</button></div>${state.notifications.length?state.notifications.map(n=>`<button class="notification-card ${n.read?'':'unread'}" data-route="${n.route||'home'}"><span>✧</span><p>${esc(n.text)}</p><small>${fmt(n.createdAt)}</small></button>`).join(''):empty('✧','All quiet','New post, campaign, follow, friend, and comment activity will appear here.','','')}`}
function renderProfile(v){const p=focusedProfileId?state.profiles[focusedProfileId]:me();if(!p){v.innerHTML=focusedProfileId?empty('♙','Profile unavailable','This profile has not reached your browser yet, or you blocked it.','',''):empty('♙','Create your adventurer profile','Build a mix-and-match avatar, choose a handle, and begin posting.','account','Create profile');return}const isMe=p.id===state.me;const posts=state.posts.filter(x=>x.authorId===p.id).sort((a,b)=>b.createdAt-a.createdAt);const following=state.follows.includes(p.id);const friend=state.friends.includes(p.id);const followers=Object.values(state.profiles).filter(x=>Array.isArray(x.following)&&x.following.includes(p.id)).length;v.innerHTML=`<section class="profile-hero public-profile"><div class="profile-cover"></div><div class="profile-main"><button class="avatar avatar-lg" data-profile-id="${p.id}">${avatarSVG(p.avatar)}</button><div><h1>${esc(p.displayName)}</h1><p class="profile-handle">@${esc(p.handle)}</p><p class="profile-bio">${esc(p.bio||'No bio yet')}</p><div class="profile-stats"><span><b>${posts.length}</b> ${posts.length===1?'post':'posts'}</span><span><b>${followers}</b> followers</span><span><b>${isMe?state.follows.length:(p.following||[]).length}</b> following</span></div></div><div class="profile-actions">${isMe?`<button class="secondary-button" data-action="edit-profile">Edit profile & avatar</button>`:`<button class="primary-button" data-follow="${p.id}">${following?'Following':'Follow'}</button><button class="secondary-button" data-friend="${p.id}">${friend?'Friends':'Add friend'}</button><button class="ghost-button" data-share-profile="${p.id}">Share profile</button><button class="danger-button" data-block="${p.id}">Block</button>`}</div></div></section><div class="tabs"><button class="active">Posts</button></div><div class="feed">${posts.length?posts.map(postHTML).join(''):empty('✦','No posts yet',isMe?'Your published tales will appear here.':'This adventurer has no active posts.','','')}</div>`} 
function modal(content,wide=false){$('#modalRoot').innerHTML=`<div class="modal-backdrop" data-close-modal><section class="modal ${wide?'wide':''}" role="dialog" aria-modal="true">${content}</section></div>`}
function closeModal(){$('#modalRoot').innerHTML=''}
function openAccountModal(edit=false){const p=me();let avatar={...(p?.avatar||defaultAvatar)};modal(`<header class="modal-head"><h2>${p?'Edit adventurer':'Create adventurer'}</h2><button class="close-button" data-close-modal>×</button></header><form id="accountForm"><div class="avatar-builder"><div class="avatar-preview"><span id="builderAvatar" class="avatar">${avatarSVG(avatar)}</span></div><div class="builder-controls">${selectField('Hair','hair',['none','swept','curly','mohawk','long','braids'],avatar.hair)}${selectField('Eyes','eyes',['round','sharp','closed','glow'],avatar.eyes)}${selectField('Mouth','mouth',['smile','neutral','fang','grin'],avatar.mouth)}${selectField('Accessory','accessory',['none','glasses','scar','horns','crown','patch'],avatar.accessory)}${colorField('Skin','skin',['#f2d0b2','#d9a276','#ad7356','#7c4934','#4a2b22'],avatar.skin)}${colorField('Hair colour','hairColor',['#171216','#3b2419','#7b3f20','#d6b061','#753356','#3a61a8','#d9d9e6'],avatar.hairColor)}${colorField('Eye colour','eyeColor',['#3ad1c7','#7fc85b','#72aaff','#c976ff','#f4c66d','#dc544f'],avatar.eyeColor)}${colorField('Background','bg',['#6b3dc0','#214d78','#2c7659','#8b3b4b','#8b5e2f','#343240'],avatar.bg)}</div></div><div class="form-grid" style="margin-top:16px"><div class="field"><label>Display name</label><input name="displayName" maxlength="40" placeholder="Your adventurer name" required value="${esc(p?.displayName||'')}"><small class="field-help">The large name shown on your profile and posts.</small></div><div class="field"><label>Handle</label><div class="handle-input"><span>@</span><input name="handle" placeholder="questkeeper" pattern="[A-Za-z0-9_]{3,20}" required value="${esc(p?.handle||'')}"></div><small class="field-help">3–20 letters, numbers, or underscores. This appears beneath your display name.</small></div><div class="field full"><label>Bio <span class="optional-label">Optional</span></label><textarea name="bio" maxlength="180" placeholder="Tell the party about your play style, favourite class, or current campaign…">${esc(p?.bio||'')}</textarea><small class="field-help">Up to 180 characters. You can change this later.</small></div></div><footer class="modal-footer"><button type="button" class="ghost-button" data-close-modal>Cancel</button><button class="primary-button">${p?'Save changes':'Create account'}</button></footer></form>`,true);$('#accountForm')._avatar=avatar;$$('[data-avatar-select]').forEach(s=>s.addEventListener('change',e=>{avatar[e.target.dataset.avatarSelect]=e.target.value;setAvatar($('#builderAvatar'),avatar)}));$$('[data-avatar-color]').forEach(b=>b.addEventListener('click',()=>{const k=b.dataset.avatarColor;avatar[k]=b.dataset.value;$$(`[data-avatar-color="${k}"]`).forEach(x=>x.classList.toggle('active',x===b));setAvatar($('#builderAvatar'),avatar)}))}
function selectField(label,key,opts,val){return `<div class="field"><label>${label}</label><select data-avatar-select="${key}">${opts.map(o=>`<option value="${o}" ${o===val?'selected':''}>${o[0].toUpperCase()+o.slice(1)}</option>`).join('')}</select></div>`}
function colorField(label,key,colors,val){return `<div class="field full"><label>${label}</label><div class="swatches">${colors.map(c=>`<button type="button" class="swatch ${c===val?'active':''}" style="background:${c}" data-avatar-color="${key}" data-value="${c}" aria-label="${c}"></button>`).join('')}</div></div>`}
function openCampaignModal(existing=null){if(!ensureAccount())return;modal(`<header class="modal-head"><h2>${existing?'Edit':'Create'} campaign</h2><button class="close-button" data-close-modal>×</button></header><form id="campaignForm"><div class="form-grid"><div class="field"><label>Campaign name</label><input name="name" required maxlength="60" value="${esc(existing?.name||'')}"></div><div class="field"><label>Game system</label><input name="system" maxlength="40" value="${esc(existing?.system||'D&D 5e')}"></div><div class="field full"><label>Description</label><textarea name="description" maxlength="500">${esc(existing?.description||'')}</textarea></div><div class="field"><label>Next session</label><input name="nextSession" type="datetime-local" value="${existing?.nextSession?new Date(existing.nextSession-new Date().getTimezoneOffset()*60000).toISOString().slice(0,16):''}"></div><div class="field"><label>Banner colour</label><input name="color" type="color" value="${existing?.color||'#7b43dc'}"></div></div><footer class="modal-footer"><button type="button" class="ghost-button" data-close-modal>Cancel</button><button class="primary-button">Save campaign</button></footer></form>`);$('#campaignForm').dataset.id=existing?.id||''}
function openComposer(type='recap',campaignId='',editing=null){if(!ensureAccount())return;let draft=editing?{...editing}:{type,style:'midnight',campaignId,title:'',body:''};modal(`<header class="modal-head"><h2>${editing?'Edit':'Create'} tale</h2><button class="close-button" data-close-modal>×</button></header><div class="editor-layout"><form id="postForm"><div class="field"><label>Post kind</label><div class="segmented" id="typeSelect">${['recap','roll','character','dialogue','lore'].map(t=>`<button type="button" data-post-type="${t}" class="${draft.type===t?'active':''}">${labelFor(t)}</button>`).join('')}</div></div><div class="field" style="margin-top:12px"><label>Blog style</label><select name="style" id="styleSelect"><option value="midnight">Midnight chronicle</option><option value="parchment">Parchment journal</option><option value="arcane">Arcane glow</option><option value="tavern">Tavern ledger</option></select></div><div id="dynamicFields" class="form-grid" style="margin-top:12px"></div><footer class="modal-footer"><button type="button" class="ghost-button" data-close-modal>Cancel</button><button class="primary-button">${editing?'Save changes':'Publish tale'}</button></footer></form><aside class="post-preview"><div class="section-title"><span>Live preview</span></div><div id="postPreview"></div></aside></div>`,true);const form=$('#postForm');form._draft=draft;form.dataset.editId=editing?.id||'';$('#styleSelect').value=draft.style;renderDynamicFields();$$('[data-post-type]').forEach(b=>b.addEventListener('click',()=>{draft.type=b.dataset.postType;$$('[data-post-type]').forEach(x=>x.classList.toggle('active',x===b));renderDynamicFields()}));$('#styleSelect').addEventListener('change',e=>{draft.style=e.target.value;previewDraft()})}
function commonFields(d){return `<div class="field full"><label>Title</label><input name="title" maxlength="120" required value="${esc(d.title||'')}"></div><div class="field full"><label>Campaign</label><select name="campaignId"><option value="">No campaign</option>${state.campaigns.map(c=>`<option value="${c.id}" ${c.id===d.campaignId?'selected':''}>${esc(c.name)}</option>`).join('')}</select></div><div class="field full"><label>Main text</label><textarea name="body" maxlength="5000" placeholder="Tell the tale…">${esc(d.body||'')}</textarea></div>`}
function renderDynamicFields(){const d=$('#postForm')._draft;let h=commonFields(d);if(d.type==='recap')h+=`<div class="field"><label>Memorable quote</label><input name="quote" value="${esc(d.quote||'')}"></div><div class="field"><label>Quote attribution</label><input name="quoteBy" value="${esc(d.quoteBy||'')}"></div>`;if(d.type==='roll')h+=`<div class="field"><label>Die</label><select name="die">${['d4','d6','d8','d10','d12','d20','d100'].map(x=>`<option ${x===(d.die||'d20')?'selected':''}>${x}</option>`).join('')}</select></div><div class="field"><label>Result</label><input name="result" type="number" min="1" max="100" required value="${esc(d.result||20)}"></div><div class="field"><label>Modifier</label><input name="modifier" type="number" min="-20" max="30" value="${esc(d.modifier||0)}"></div><div class="field"><label>Check / save</label><input name="check" placeholder="Persuasion check" value="${esc(d.check||'')}"></div>`;if(d.type==='character')h+=`<div class="field"><label>Character name</label><input name="characterName" required value="${esc(d.characterName||'')}"></div><div class="field"><label>Level</label><input name="level" type="number" min="1" max="30" value="${esc(d.level||1)}"></div><div class="field"><label>Race / ancestry</label><input name="race" value="${esc(d.race||'')}"></div><div class="field"><label>Class</label><input name="className" value="${esc(d.className||'')}"></div>${['str','dex','con','int','wis','cha'].map(k=>`<div class="field"><label>${k.toUpperCase()}</label><input name="${k}" type="number" min="1" max="30" value="${esc(d[k]||10)}"></div>`).join('')}<div class="field full"><label>Character avatar</label><button type="button" class="secondary-button" data-action="character-avatar">Customize character avatar</button></div>`;if(d.type==='dialogue')h+=`<div class="field full"><label>Dialogue line</label><textarea name="quote" required placeholder="I cast Detect Thoughts on the moon.">${esc(d.quote||'')}</textarea></div><div class="field"><label>Speaker</label><input name="speaker" required value="${esc(d.speaker||'')}"></div><div class="field"><label>Context</label><input name="context" placeholder="Right before everything went wrong" value="${esc(d.context||'')}"></div>`;if(d.type==='lore')h+=`<div class="field"><label>Lore category</label><select name="loreCategory">${['Location','Faction','Artefact','Deity','Monster','NPC','History','Secret'].map(x=>`<option ${x===d.loreCategory?'selected':''}>${x}</option>`).join('')}</select></div><div class="field full"><label>Deep lore</label><textarea name="loreDetail" placeholder="Add the hidden details…">${esc(d.loreDetail||'')}</textarea></div>`;$('#dynamicFields').innerHTML=h;$$('#postForm input,#postForm textarea,#postForm select').forEach(el=>el.addEventListener('input',syncDraft));previewDraft()}
function syncDraft(){const f=new FormData($('#postForm'));for(const [k,v] of f)$('#postForm')._draft[k]=v;previewDraft()}
function previewDraft(){const d=$('#postForm')._draft;const p={id:'preview',authorId:state.me,createdAt:now(),reactions:[],comments:[],shares:0,...d};$('#postPreview').innerHTML=postHTML(p);$$('#postPreview button').forEach(b=>b.disabled=true)}
function openCharacterAvatar(){const d=$('#postForm')._draft;let a={...(d.characterAvatar||me()?.avatar||defaultAvatar)};modal(`<header class="modal-head"><h2>Character avatar</h2><button class="close-button" data-close-modal>×</button></header><div class="avatar-builder"><div class="avatar-preview"><span id="builderAvatar" class="avatar">${avatarSVG(a)}</span></div><div class="builder-controls">${selectField('Hair','hair',['none','swept','curly','mohawk','long','braids'],a.hair)}${selectField('Eyes','eyes',['round','sharp','closed','glow'],a.eyes)}${selectField('Mouth','mouth',['smile','neutral','fang','grin'],a.mouth)}${selectField('Accessory','accessory',['none','glasses','scar','horns','crown','patch'],a.accessory)}${colorField('Skin','skin',['#f2d0b2','#d9a276','#ad7356','#7c4934','#4a2b22'],a.skin)}${colorField('Hair colour','hairColor',['#171216','#3b2419','#7b3f20','#d6b061','#753356','#3a61a8'],a.hairColor)}${colorField('Eye colour','eyeColor',['#3ad1c7','#7fc85b','#72aaff','#c976ff','#f4c66d'],a.eyeColor)}${colorField('Background','bg',['#6b3dc0','#214d78','#2c7659','#8b3b4b','#8b5e2f'],a.bg)}</div></div><footer class="modal-footer"><button class="primary-button" id="useCharacterAvatar">Use avatar</button></footer>`,true);$$('[data-avatar-select]').forEach(s=>s.addEventListener('change',e=>{a[e.target.dataset.avatarSelect]=e.target.value;setAvatar($('#builderAvatar'),a)}));$$('[data-avatar-color]').forEach(b=>b.addEventListener('click',()=>{a[b.dataset.avatarColor]=b.dataset.value;setAvatar($('#builderAvatar'),a)}));$('#useCharacterAvatar').onclick=()=>{d.characterAvatar=a;closeModal();openComposer('character',d.campaignId,d.id?d:null)}}
function openCampaign(id){const c=state.campaigns.find(x=>x.id===id);if(!c)return;const posts=state.posts.filter(p=>p.campaignId===id);modal(`<header class="modal-head"><h2>${esc(c.name)}</h2><button class="close-button" data-close-modal>×</button></header><div class="campaign-banner" style="--accent:${c.color}">${esc(c.name)}</div><p>${esc(c.description||'No description')}</p><p>${esc(c.system||'D&D')} · ${c.nextSession?new Date(c.nextSession).toLocaleString():'No session scheduled'}</p><div class="card-actions"><button class="secondary-button" data-edit-campaign="${c.id}">Edit campaign</button><button class="primary-button" data-compose-campaign="${c.id}">New post</button></div><div class="feed" style="margin-top:16px">${posts.length?posts.map(postHTML).join(''):empty('✦','No campaign posts','Create a recap, roll, character, dialogue, or lore entry for this campaign.','','')}</div>`,true)}
function showPostMenu(id,btn){const p=state.posts.find(x=>x.id===id);if(!p)return;const r=btn.getBoundingClientRect();$('#menuRoot').innerHTML=`<div class="menu" style="top:${Math.min(innerHeight-220,r.bottom+5)}px;left:${Math.min(innerWidth-190,r.right-180)}px">${own(p)?`<button data-edit-post="${id}">Edit post</button><button class="danger" data-delete-post="${id}">Delete post</button>`:''}<button data-copy-post="${id}">Copy post text</button><button data-save="${id}">${state.saved.includes(id)?'Remove from saved':'Save post'}</button>${!own(p)?`<button data-report-post="${id}">Report post</button>`:''}</div>`}
function quickRoll(){const value=1+Math.floor(Math.random()*20);$('#headerDieValue').textContent=value;$$('.hero-die span').forEach(x=>x.textContent=value);toast(`You rolled a ${value} on a d20`)}
async function shareText(url,title='Questlog'){try{if(navigator.share){await navigator.share({title,text:title,url});return true}await navigator.clipboard.writeText(url);return true}catch(e){if(e?.name==='AbortError')return false;try{await navigator.clipboard.writeText(url);return true}catch{return false}}}
async function sharePost(id){const p=state.posts.find(x=>x.id===id);if(!p)return false;p.shareCode=p.shareCode||makeShareCode();save();publishPost(p);const base=location.href.split('#')[0];const url=`${base}#post/${encodeURIComponent(p.shareCode)}`;const text=`${p.title} — Questlog code ${p.shareCode}`;try{if(navigator.share){await navigator.share({title:p.title,text,url});toast(`Shared code ${p.shareCode}`)}else{await navigator.clipboard.writeText(url);toast(`Post link copied · ${p.shareCode}`)}return true}catch(e){if(e?.name!=='AbortError')toast('Could not share this post');return false}}
function submitAccount(form){const fd=Object.fromEntries(new FormData(form));const old=me();const id=old?.id||uid();const handle=fd.handle.toLowerCase();const clash=Object.values(state.profiles).some(p=>p.id!==id&&p.handle===handle);if(clash){toast('That handle is already in use');return}state.me=id;state.profiles[id]={id,displayName:fd.displayName.trim(),handle,bio:fd.bio.trim(),avatar:form._avatar,following:[...state.follows],createdAt:old?.createdAt||now(),updatedAt:now()};save();closeModal();notify(old?'Profile updated':'Adventurer profile created','profile');publishProfile();render()}
function submitCampaign(form){const fd=Object.fromEntries(new FormData(form));const id=form.dataset.id||uid();const prev=state.campaigns.find(c=>c.id===id);const c={id,ownerId:state.me,name:fd.name.trim(),system:fd.system.trim(),description:fd.description.trim(),nextSession:fd.nextSession?new Date(fd.nextSession).getTime():null,color:fd.color,createdAt:prev?.createdAt||now()};state.campaigns=prev?state.campaigns.map(x=>x.id===id?c:x):[c,...state.campaigns];save();closeModal();notify(`${prev?'Updated':'Created'} campaign “${c.name}”`,'campaigns');render()}
function submitPost(form){syncDraft();const d=form._draft;const id=form.dataset.editId||uid();const prev=state.posts.find(p=>p.id===id);const p={...prev,...d,id,shareCode:prev?.shareCode||makeShareCode(),authorId:state.me,createdAt:prev?.createdAt||now(),updatedAt:now(),reactions:prev?.reactions||[],comments:prev?.comments||[],shares:prev?.shares||0};state.posts=prev?state.posts.map(x=>x.id===id?p:x):[p,...state.posts];save();closeModal();notify(`${prev?'Updated':'Published'} “${p.title}”`,'home');publishPost(p);toast(`Shared with connected users · ${p.shareCode}`);go('home')}
function makeShareCode(){const alphabet='ABCDEFGHJKLMNPQRSTUVWXYZ23456789';const bytes=new Uint8Array(8);crypto.getRandomValues(bytes);return [...bytes].map(b=>alphabet[b%alphabet.length]).join('')}
function mergeProfile(profile){if(!profile?.id)return false;const old=state.profiles[profile.id];if(!old||Number(profile.updatedAt||profile.createdAt||0)>=Number(old.updatedAt||old.createdAt||0)){state.profiles[profile.id]=profile;return true}return false}
function mergePost(post){if(!post?.id||!post.createdAt||post.createdAt+POST_TTL<=now())return false;const i=state.posts.findIndex(p=>p.id===post.id);if(i<0){state.posts.push(post);return true}if(Number(post.updatedAt||post.createdAt)>=Number(state.posts[i].updatedAt||state.posts[i].createdAt)){state.posts[i]=post;return true}return false}
function p2pSnapshot(){return {posts:state.posts.filter(p=>p.createdAt+POST_TTL>now()),profiles:state.profiles,sentAt:now()}}
async function initP2P(attempt=0){
  p2pPhase=attempt?'retrying':'connecting';renderChrome();
  try{
    // The official CDN entry uses Trystero's default Nostr signalling strategy.
    const {joinRoom}=await import('https://esm.run/trystero');
    p2pRoom=joinRoom({appId:P2P_APP_ID},P2P_ROOM_ID);
    const postAction=p2pRoom.makeAction('post');
    const profileAction=p2pRoom.makeAction('profile');
    const syncAction=p2pRoom.makeAction('sync');
    const requestAction=p2pRoom.makeAction('request');
    p2pSendPost=postAction.send;p2pSendProfile=profileAction.send;p2pSendSync=syncAction.send;p2pSendRequest=requestAction.send;
    postAction.onMessage=post=>{if(mergePost(post)){save({broadcast:false});render()}};
    profileAction.onMessage=profile=>{if(mergeProfile(profile)){save({broadcast:false});render()}};
    syncAction.onMessage=data=>{let changed=false;Object.values(data?.profiles||{}).forEach(p=>{changed=mergeProfile(p)||changed});(data?.posts||[]).forEach(p=>{changed=mergePost(p)||changed});if(changed){save({broadcast:false});render()}};
    requestAction.onMessage=(request,peerId)=>{if(request?.postId){const p=state.posts.find(x=>x.id===request.postId||x.shareCode===request.postId);if(p)p2pSendPost(p,peerId)}else p2pSendSync(p2pSnapshot(),peerId)};
    p2pRoom.onPeerJoin=peerId=>{p2pPeers.add(peerId);p2pPhase='ready';p2pSendSync(p2pSnapshot(),peerId);p2pSendRequest({all:true},peerId);renderChrome()};
    p2pRoom.onPeerLeave=peerId=>{p2pPeers.delete(peerId);renderChrome()};
    p2pPhase='ready';
    setTimeout(()=>p2pSendRequest({all:true}),900);
    setTimeout(()=>p2pSendRequest({all:true}),3500);
    renderChrome();
  }catch(e){
    p2pRoom=null;p2pPhase='offline';console.warn('P2P sync unavailable; retry scheduled.',e);renderChrome();
    const delay=Math.min(30000,3000*(attempt+1));setTimeout(()=>initP2P(attempt+1),delay);
  }
}

function mergeSnapshot(data){let changed=false;Object.values(data?.profiles||{}).forEach(p=>{changed=mergeProfile(p)||changed});(data?.posts||[]).forEach(p=>{changed=mergePost(p)||changed});if(changed){save({broadcast:false});render()}return changed}
if(localChannel){
  localChannel.onmessage=e=>{if(e.data?.from===TAB_ID)return;if(e.data?.type==='snapshot')mergeSnapshot(e.data.data);if(e.data?.type==='hello'){localChannel.postMessage({type:'snapshot',from:TAB_ID,data:p2pSnapshot()})}};
  localChannel.postMessage({type:'hello',from:TAB_ID});
}
window.addEventListener('storage',e=>{if(e.key!==APP_KEY||!e.newValue)return;try{const incoming=JSON.parse(e.newValue);mergeSnapshot({posts:incoming.posts||[],profiles:incoming.profiles||{}})}catch{}});
window.addEventListener('online',()=>{if(!p2pRoom)initP2P()});
function publishProfile(){const p=me();if(!p||!p2pSendProfile)return;p.updatedAt=now();p2pSendProfile(p)}
function publishPost(p){if(!p2pSendPost)return;p2pSendPost(p)}

document.addEventListener('click',e=>{const b=e.target.closest('button,[data-route],[data-action]');if(!b)return;if(b.dataset.route){go(b.dataset.route);return}if(b.dataset.action==='open-composer'){openComposer();return}if(b.dataset.action==='new-campaign'){openCampaignModal();return}if(b.dataset.action==='account'||b.dataset.action==='edit-profile'){openAccountModal(true);return}if(b.dataset.action==='quick-roll'){quickRoll();return}if(b.dataset.action==='clear-notifications'){state.notifications=[];save();render();return}if(b.dataset.action==='character-avatar'){openCharacterAvatar();return}if(b.dataset.action==='compose-lore'){openComposer('lore');return}if(b.dataset.closeModal!==undefined||e.target.matches('[data-close-modal]')){if(e.target===e.currentTarget||b.dataset.closeModal!==undefined)closeModal();return}if(b.dataset.composeType){openComposer(b.dataset.composeType);return}if(b.dataset.composeCampaign){openComposer('recap',b.dataset.composeCampaign);return}if(b.dataset.feed){currentFeed=b.dataset.feed;render();return}if(b.dataset.campaignId){openCampaign(b.dataset.campaignId);return}if(b.dataset.editCampaign){const c=state.campaigns.find(x=>x.id===b.dataset.editCampaign);closeModal();openCampaignModal(c);return}if(b.dataset.morePost){showPostMenu(b.dataset.morePost,b);return}if(b.dataset.react){if(!ensureAccount())return;const p=state.posts.find(x=>x.id===b.dataset.react);p.reactions=p.reactions||[];p.reactions=p.reactions.includes(state.me)?p.reactions.filter(x=>x!==state.me):[...p.reactions,state.me];p.updatedAt=now();save();publishPost(p);render();return}if(b.dataset.commentToggle){$(`#comments-${b.dataset.commentToggle}`)?.classList.toggle('hidden');return}if(b.dataset.share){sharePost(b.dataset.share).then(shared=>{if(!shared)return;const p=state.posts.find(x=>x.id===b.dataset.share);if(p){p.shares=(p.shares||0)+1;save();render()}});return}if(b.dataset.save){const id=b.dataset.save;state.saved=state.saved.includes(id)?state.saved.filter(x=>x!==id):[...state.saved,id];save();$('#menuRoot').innerHTML='';render();return}if(b.dataset.editPost){const p=state.posts.find(x=>x.id===b.dataset.editPost);$('#menuRoot').innerHTML='';openComposer(p.type,p.campaignId,p);return}if(b.dataset.deletePost){state.posts=state.posts.filter(x=>x.id!==b.dataset.deletePost);state.saved=state.saved.filter(x=>x!==b.dataset.deletePost);save();$('#menuRoot').innerHTML='';render();toast('Post deleted');return}if(b.dataset.copyPost){const p=state.posts.find(x=>x.id===b.dataset.copyPost);navigator.clipboard.writeText(`${p.title}\n\n${p.body||''}`);toast('Post text copied');$('#menuRoot').innerHTML='';return}if(b.dataset.reportPost){toast('Post hidden and report stored locally');state.posts=state.posts.filter(x=>x.id!==b.dataset.reportPost);save();$('#menuRoot').innerHTML='';render();return}if(b.dataset.follow){if(!ensureAccount())return;const id=b.dataset.follow;state.follows=state.follows.includes(id)?state.follows.filter(x=>x!==id):[...state.follows,id];const mine=me();if(mine){mine.following=[...state.follows];mine.updatedAt=now();publishProfile()}save();notify(`${state.follows.includes(id)?'Followed':'Unfollowed'} ${state.profiles[id]?.displayName||'adventurer'}`,'discover');render();return}if(b.dataset.friend){if(!ensureAccount())return;const id=b.dataset.friend;state.friends=state.friends.includes(id)?state.friends.filter(x=>x!==id):[...state.friends,id];notify(`${state.friends.includes(id)?'Added':'Removed'} ${state.profiles[id]?.displayName||'adventurer'} ${state.friends.includes(id)?'as a friend':'from friends'}`,'discover');render();return}if(b.dataset.profileId){location.hash=`profile/${encodeURIComponent(b.dataset.profileId)}`;return}if(b.dataset.shareProfile){const p=state.profiles[b.dataset.shareProfile];const url=`${location.origin}${location.pathname}#profile/${encodeURIComponent(p.id)}`;shareText(url,`${p.displayName} on Questlog`).then(()=>toast('Profile link ready'));return}if(b.dataset.block){const id=b.dataset.block;state.blocked=[...new Set([...state.blocked,id])];state.follows=state.follows.filter(x=>x!==id);state.friends=state.friends.filter(x=>x!==id);save();go('discover');toast('User blocked');return}if(b.dataset.openPost){go('home');setTimeout(()=>document.querySelector(`[data-post-id="${b.dataset.openPost}"]`)?.scrollIntoView({behavior:'smooth'}),50)}});
document.addEventListener('submit',e=>{e.preventDefault();if(e.target.id==='accountForm')submitAccount(e.target);if(e.target.id==='campaignForm')submitCampaign(e.target);if(e.target.id==='postForm')submitPost(e.target);if(e.target.dataset.commentForm){if(!ensureAccount())return;const p=state.posts.find(x=>x.id===e.target.dataset.commentForm);const input=e.target.elements.comment;p.comments=p.comments||[];p.comments.push({id:uid(),authorId:state.me,text:input.value.trim(),createdAt:now()});input.value='';p.updatedAt=now();save();publishPost(p);notify(`Comment added to “${p.title}”`,'home');render();setTimeout(()=>{$(`#comments-${p.id}`)?.classList.remove('hidden')},0)}});
document.addEventListener('click',e=>{if(!e.target.closest('.menu')&&!e.target.closest('[data-more-post]'))$('#menuRoot').innerHTML=''});
$('#notificationsButton').addEventListener('click',()=>go('notifications'));$('#profileButton').addEventListener('click',()=>go('profile'));$('#globalSearch').addEventListener('input',()=>{if(route==='discover')renderDiscover($('#appView'));else{const q=$('#globalSearch').value.toLowerCase();$$('.post').forEach(p=>p.classList.toggle('hidden',!p.textContent.toLowerCase().includes(q)))}});document.addEventListener('keydown',e=>{if((e.metaKey||e.ctrlKey)&&e.key.toLowerCase()==='k'){e.preventDefault();$('#globalSearch').focus()}if(e.key==='Escape'){closeModal();$('#menuRoot').innerHTML=''}});
(()=>{const parts=(location.hash.slice(1)||'home').split('/');route=parts[0];focusedPostId=route==='post'?decodeURIComponent(parts.slice(1).join('/')):null;focusedProfileId=route==='profile'&&parts[1]?decodeURIComponent(parts.slice(1).join('/')):null})();render();initP2P();
